from typing import List, Dict, Any
from leann.api import LeannSearcher, SearchResult
from collections import defaultdict

def search_and_group_by_metadata(
    index_path: str,
    query: str,
    group_by_field: str,
    top_k: int = 10
) -> Dict[str, List[SearchResult]]:
    """Search in an index and group results by a metadata field."""
    try:
        searcher = LeannSearcher(index_path)
        results = searcher.search(query, top_k=top_k)

        grouped_results = defaultdict(list)
        for result in results:
            if group_by_field in result.metadata:
                group_value = result.metadata[group_by_field]
                grouped_results[group_value].append(result)

        return dict(grouped_results)

    except FileNotFoundError:
        return {}

from typing import List, Dict, Any
from leann.api import LeannSearcher
from collections import defaultdict

def search_and_aggregate_scores(
    index_path: str,
    query: str,
    aggregate_by_field: str,
    top_k: int = 10
) -> Dict[str, Dict[str, float]]:
    """Search in an index and aggregate scores by a metadata field."""
    try:
        searcher = LeannSearcher(index_path)
    except FileNotFoundError:
        raise FileNotFoundError(f"Index file not found: {index_path}")

    results = searcher.search(query, top_k=top_k)

    groups = defaultdict(lambda: {'count': 0, 'sum': 0.0, 'max': -float('inf'), 'min': float('inf')})

    for result in results:
        field_value = result.metadata.get(aggregate_by_field)
        if field_value is None:
            continue
        groups[field_value]['count'] += 1
        groups[field_value]['sum'] += result.score
        current_score = result.score
        if current_score > groups[field_value]['max']:
            groups[field_value]['max'] = current_score
        if current_score < groups[field_value]['min']:
            groups[field_value]['min'] = current_score

    # Calculate average for each group
    for field_value in groups:
        groups[field_value]['avg_score'] = groups[field_value]['sum'] / groups[field_value]['count']

    # Convert to the required format
    result_dict = {}
    for field_value, stats in groups.items():
        result_dict[field_value] = {
            'count': stats['count'],
            'avg_score': stats['avg_score'],
            'max_score': stats['max'],
            'min_score': stats['min']
        }

    return result_dict

