from typing import List, Dict, Any
from leann.api import LeannBuilder
from pathlib import Path

def build_index_with_metadata_validation(
    documents: List[Dict[str, Any]],
    index_path: str,
    required_metadata_fields: List[str] = None,
    backend_name: str = "hnsw"
) -> str:
    """Build a LEANN index with validation of required metadata fields."""

    # Validate documents list is not empty
    if not documents:
        raise ValueError("Documents list is empty")

    # Validate required metadata fields if specified
    if required_metadata_fields is not None:
        for doc in documents:
            if 'metadata' not in doc:
                raise ValueError("Document missing metadata field")
            doc_metadata = doc['metadata']
            for field in required_metadata_fields:
                if field not in doc_metadata:
                    raise ValueError(f"Missing required metadata field: {field}")

    # Initialize builder and add documents
    builder = LeannBuilder(backend_name=backend_name)

    for doc in documents:
        text = doc['text']
        metadata = doc.get('metadata', {})
        builder.add_text(text, metadata=metadata)

    # Build index at specified path
    index_path_obj = Path(index_path)
    builder.build_index(index_path_obj)

    return str(index_path_obj)

